form:Form.form:Scripts:
		var arrFILTER;
var arrSELECTED;


//Actualiza la lista con el nuevo ARRAY
function refreshSelected()
{              
 	var page=Ctrl("listSELECTED").Page;
	Ctrl("listSELECTED").IDs=arrSELECTED;
	Ctrl("listSELECTED").ResetSQL();
	Ctrl("listSELECTED").GotoPage(page);

	enable_buttons();
}

function enable_buttons(msg)
{ 
	if (Ctrl("listFILTER").SetMessage) Ctrl("listFILTER").SetMessage(null);
  CtrlEnabled("listFILTER_Delete", Ctrl("arrcheckFILTER").CountRow()==0?false:true);
  CtrlEnabled("listFILTER_Clear" , true);
	CtrlEnabled("ADD_ALL"          , arrFILTER.length==0?false:true);
	CtrlEnabled("ADD"              , Ctrl("arrcheckFILTER").CountRow()==0?false:true);

	CtrlEnabled("listSELECTED_Delete", Ctrl("arrcheckSELECTED").CountRow()==0?false:true);
	CtrlEnabled("listSELECTED_Clear" , true);
	CtrlEnabled("DEL_ALL"            , arrSELECTED.length==0?false:true);
	CtrlEnabled("DEL"                , Ctrl("arrcheckSELECTED").CountRow()==0?false:true);

  CtrlEnabled("vgroupDatosPers"  , true);
  CtrlEnabled("vgroupDatosCustom", true);        

  enable_custom_buttons();
  loadingMessage(false, null);
  formEnabled = true;

  Ctrl("filtrados").SetXValue("Legajos Filtrados: "+arrFILTER.length+(msg?msg:""));
	Ctrl("incluidos").SetXValue("Legajos Incluidos: "+arrSELECTED.length);
}

function internal_find()
{ 
  var auxArr, auxArr2;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	auxArr2=new Array();
	copiar(auxArr2, auxArr);

	//Obtiene los Elementos en Comun.
	intersect(auxArr , arrFILTER);
	intersect(auxArr2, arrSELECTED);		

	if (auxArr.length==0 && auxArr2.length==0) 
	{
		alert("No se encontro ningun registro.");
		return;
	}

	if (auxArr.length!=0)
		Ctrl("listFILTER").SetXValue(auxArr[0]);

	if (auxArr2.length!=0)
		Ctrl("listSELECTED").SetXValue(auxArr2[0]);
}


function ONLOAD()
{
	var t, ROW, VALUES;
	arrFILTER = new Array();
	arrSELECTED = new Array();

	//Valores Iniciales
	for (t=0; t<Ctrl("arrSELECTED").CountRow(); t++)
	{
		ROW=Ctrl("arrSELECTED").GetRow(t);
		VALUES=ROW.GetAttr("VALUES").split(",");
		for (d=0; d<VALUES.length; d++)
			if (VALUES[d]!="")
				arrSELECTED.push(VALUES[d]);
	} 

	refreshSelected();
	refreshList();
}

function ONLOAD_custom()
{
}

function POST_exec_qry(resultArray)
{
	remove(resultArray, arrSELECTED);
}

function FillArray(numByRow)
{
	var t,n,values,sep,row,p;

	Ctrl("arrSELECTED").DelAllRow(); 

	values=""; sep="";
	for (t=0,n=0,p=0; t<arrSELECTED.length; t++, n++)
	{
		if (n>=numByRow)
		{              
			p++;
			row=Ctrl("arrSELECTED").AddRow()
			row.SetAttr("id", p);
			row.SetAttr("VALUES", values);
			values=""; sep=""; n=0;
		}                  

		values+=sep+arrSELECTED[t];
		sep=",";
	}
	if (values!="") 
	{      
		p++;
		row=Ctrl("arrSELECTED").AddRow()
		row.SetAttr("id", p);
		row.SetAttr("VALUES", values);
	}

}

function ADD()
{           
	for (var X=0; X<arrFILTER.length; X++)
	{
		if (Ctrl("arrcheckFILTER").GetRowByAttr("ID",arrFILTER[X])!=null)
		{                        
			arrSELECTED.push(arrFILTER[X]);
			arrFILTER.splice(X,1);
			X--;
		}
	}

	Ctrl("listFILTER").SetXValue("");
 	Ctrl("arrcheckFILTER").DelAllRow();
	refreshList();
	refreshSelected();
}

function ADD_ALL()
{                 
	Ctrl("listFILTER").SetXValue("");
	Ctrl("listSELECTED").SetXValue(""); 
	Ctrl("arrcheckFILTER").DelAllRow();

	union(arrSELECTED, arrFILTER);
	arrFILTER=new Array();
	refreshSelected();
	refreshList();
}

function DEL()
{              
	for (var X=0; X<arrSELECTED.length; X++)
	{
		if (Ctrl("arrcheckSELECTED").GetRowByAttr("ID",arrSELECTED[X])!=null)
		{                        
			arrFILTER.push(arrSELECTED[X]);
			arrSELECTED.splice(X,1);
			X--;
		}
	}

	Ctrl("listSELECTED").SetXValue("");
 	Ctrl("arrcheckSELECTED").DelAllRow();
	refreshList();
	refreshSelected();
}

function DEL_ALL()
{
	Ctrl("listFILTER").SetXValue("");
	Ctrl("listSELECTED").SetXValue("");
	Ctrl("arrcheckSELECTED").DelAllRow();

	union(arrFILTER, arrSELECTED);
	arrSELECTED=new Array();
	refreshSelected();
	refreshList();
}


//Elimino iten del FILTRO
function delSELECTED()
{                      
	for (var X=0; X<arrSELECTED.length; X++)
	{
		if (Ctrl("arrcheckSELECTED").GetRowByAttr("ID",arrSELECTED[X])!=null)
		{                        
			arrSELECTED.splice(X,1);
			X--;
		}
	}

	Ctrl("listSELECTED").SetXValue("");
 	Ctrl("arrcheckSELECTED").DelAllRow();
	refreshSelected();
}

//Limpio la Lista del FILTRO
function clearSELECTED()
{  
	for (var X=0; X<arrSELECTED.length; X++)
	{
		if (Ctrl("arrcheckSELECTED").GetRowByAttr("ID",arrSELECTED[X])==null)
		{                        
			arrSELECTED.splice(X,1);
			X--;
		}
	}

	Ctrl("listSELECTED").SetXValue("");
 	Ctrl("arrcheckSELECTED").DelAllRow();
	refreshSelected();
}                 

function checkSELECTED()
{    
	var X=Ctrl("listSELECTED").GetXValue();
	if (X!="" && Ctrl("listSELECTED").LastColumnClick!="SEL")
	{                                                  
		if (Ctrl("arrcheckSELECTED").GetRowByAttr("ID",X)==null) Ctrl("arrcheckSELECTED").AddRow().SetAttr("ID",X);
		                                                    else Ctrl("arrcheckSELECTED").DelRowByAttr("ID",X);    

		Ctrl("listSELECTED").SetXValue("");
		refreshSelected();
	} else           
		enable_buttons();
}

//Deschequeo TOTAL
function unmarkSELECTED()
{
	Ctrl("listSELECTED").SetXValue("");
 	Ctrl("arrcheckSELECTED").DelAllRow();
	refreshSelected();
}


function ACCEPT()
{
	Ctrl("main").DoEvent("ACCEPT");
}

function CANCEL()
{
	Ctrl("main").DoEvent("CANCEL");
}
